export const questionBank: Question[] = [
  ...bab1,
  ...bab2,
  ...bab3,
  ...bab4,
  ...bab5,
  ...bab6,
];

// Untuk kompatibilitas dengan kode lama yang mengimpor `questions` langsung
// (sebaiknya pindah ke getRandomQuestions() di halaman quiz)
export const questions = questionBank;

/**
 * Mengambil `count` soal secara acak dari seluruh bank soal (300 soal),
 * tanpa duplikasi, menggunakan algoritma Fisher–Yates shuffle.
 */
export function getRandomQuestions(count: number = 5): Question[] {
  const pool = [...questionBank];

  for (let i = pool.length - 1; i > 0; i--) {
    const j = Math.floor(Math.random() * (i + 1));
    [pool[i], pool[j]] = [pool[j], pool[i]];
  }

  return pool.slice(0, count);
}

/**
 * Varian yang mengambil `count` soal secara acak, tetapi dijamin
 * merata dari tiap bab (opsional, kalau nanti perlu quiz yang
 * representasinya seimbang lintas topik).
 */
export function getRandomQuestionsBalanced(count: number = 5): Question[] {
  const chapters = [bab1, bab2, bab3, bab4, bab5, bab6];
  const perChapter = Math.floor(count / chapters.length);
  const remainder = count % chapters.length;

  const result: Question[] = [];

  chapters.forEach((chapter, idx) => {
    const shuffled = [...chapter];
    for (let i = shuffled.length - 1; i > 0; i--) {
      const j = Math.floor(Math.random() * (i + 1));
      [shuffled[i], shuffled[j]] = [shuffled[j], shuffled[i]];
    }
    const take = perChapter + (idx < remainder ? 1 : 0);
    result.push(...shuffled.slice(0, take));
  });

  return result;
}